import React from "react"
import Typewriter from "typewriter-effect"
import styled from "styled-components"

const SectionHeader = React.forwardRef(({ inView }, ref) => {
  return (
    <Header ref={ref}>
      {inView &&
        <Typewriter
          onInit={(typewriter) => {
            typewriter
              .changeDelay(50)
              .typeString("Projects")
              .callFunction(state => state.elements.cursor.style.display = "none")
              .pauseFor(200)
              .callFunction(state => state.elements.container.style.backgroundSize = "100% 3px")
              .start()
          }}
        />
      }
    </Header>
  )
})

const Header = styled.h3`
  margin: 0.5em;
  font-weight: 400;
  width: fit-content;
  color: white;
  font-size: 3em;

  & div {
    background: linear-gradient(0deg, white, white) bottom center no-repeat;
    background-size: 0px 3px;
    transition: background-size 500ms;
    background-position: right bottom;
    padding-bottom: 0.1em;
  }
`

export default SectionHeader
